<template>
  <div>
    <div
      v-for="(item, idx) in showTabs"
      :key="'tab-' + idx"
      :ref="item.url"
      class="fixed top-16 w-full z-50"
      :style="{
        transform: `translate(${tabStore.getoffSetX(
          item.url
        )}px, ${tabStore.getoffSetY(item.url)}px)`,
      }"
    >
      <div
        class="
          max-w-7xl
          m-0
          relative
          mx-auto
          px-4
          py-3
          bg-white
          border-2
          shadow-xl
          flex flex-col
        "
        style="height: 40rem"
        @click.stop="show(item.url)"
      >
        <div
          class="
            flex
            w-full
            py-6
            border-b-2
            shadow-sm
            justify-between
            items-center
            cursor-pointer
          "
          @mousedown="dragTabStart($event, item.url)"
          @mouseup="dragTabEnd($event, item.url)"
          @touchstart="dragTabStart($event, item.url)"
          @tounchend="dragTabEnd($event, item.url)"
        >
          <!-- 左侧菜单栏 -->
          <div class="text-white text-opacity-0 hover:text-opacity-100">
            <div class="flex">
              <div
                @click="close(item.url)"
                class="
                  bg-red-600
                  cursor-pointer
                  rounded-full
                  h-4
                  w-4
                  mx-1
                  flex
                  items-center
                  justify-center
                "
              >
                x
              </div>
              <div
                @click="hide(item.url)"
                class="
                  bg-yellow-600
                  cursor-pointer
                  rounded-full
                  h-4
                  w-4
                  mx-1
                  flex
                  items-center
                  justify-center
                "
              >
                -
              </div>
              <div
                @click="show"
                class="
                  bg-green-600
                  cursor-pointer
                  rounded-full
                  h-4
                  w-4
                  mx-1
                  flex
                  items-center
                  justify-center
                "
              >
                Ο
              </div>
            </div>
          </div>
          <div class="text-right">
            <button @click.stop="open(item.url)">去官网打开</button>
          </div>
        </div>
        <div :id="'panel' + idx" class="w-full flex-grow">
          <iframe style="height: 100%; width: 100%" :src="item.url"></iframe>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { end } from "@popperjs/core";
class MultiTabStore {
  constructor() {
    this.tabs = new Map(); // ismove, offsetX, offsetY, curOffsetX, curOffsetY, 支持新增，删除对应idx
  }
  addTab(key) {
    if (this.tabs.has(key)) {
      console.log("addTab key重复");
      return;
    }
    this.tabs.set(key, {
      ismove: false,
      offSetX: 0,
      offSetY: 0,
      curOffsetX: 0,
      curOffsetY: 0,
    });
  }
  deleteTab(key) {
    this.tabs.delete(key);
  }
  getismove(key) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    return this.tabs.get(key).ismove;
  }
  setismove(key, val) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    this.tabs.get(key).ismove = val;
  }
  getoffSetX(key) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    return this.tabs.get(key).offSetX;
  }
  setoffSetX(key, val) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    this.tabs.get(key).offSetX = val;
  }
  getoffSetY(key) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    return this.tabs.get(key).offSetY;
  }
  setoffSetY(key, val) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    this.tabs.get(key).offSetY = val;
  }
  getcurOffsetX(key) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    return this.tabs.get(key).curOffsetX;
  }
  setcurOffsetX(key, val) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    this.tabs.get(key).curOffsetX = val;
  }
  getcurOffsetY(key) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    return this.tabs.get(key).curOffsetY;
  }
  setcurOffsetY(key, val) {
    if (!this.tabs.has(key)) {
      console.log("addTab key不存在");
      return;
    }
    this.tabs.get(key).curOffsetY = val;
  }
}

export default {
  name: "ComTab",
  data() {
    return {
      // showTab: false,
      ismove: false,
      // tabSrc: "",
      message: "",
      // offSetX: 0,
      // offSetY: 0,
      // curOffsetX: 0,
      // curOffsetY: 0,
      curKey: "",
      entryX: 0,
      entryY: 0,
      tabStore: new MultiTabStore(),
    };
  },
  computed: {
    /**
     * [
     * {url: ..., icon: ...}
     * ]
     */
    // tabs() {
    //   let tabs = this.$store.getters["tab/tabs"];
    //   for (let i of tabs) {
    //     this.tabStore.addTab(i.url);
    //   }
    //   return tabs;
    // },
    showTabs() {
      let showTabs = this.$store.getters["tab/showTabs"];
      let tabs = this.$store.getters["tab/tabs"];
      for (let i of tabs) {
        this.tabStore.addTab(i.url);
      }
      // for (let i of tabs) {
      //   this.tabStore.addTab(i.url);
      // }
      return showTabs;
    },
    frame() {
      //  <iframe :src="tabSrc" style="height: 100%; width: 100%"></iframe>
      let frame = document.createElement("iframe");
      frame.setAttribute("style", "height: 100%; width: 100%");
      return frame;
    },
  },
  methods: {
    open(url) {
      window.open(url);
    },
    show(key) {
      for (let idx in this.tabs) {
        let item = this.tabs[idx];
        if (item.url == key) {
          this.$refs[item.url][0].classList.add("z-100");
        } else {
          this.$refs[item.url][0].classList.remove("z-100");
        }
      }
    },
    close(key) {
      this.tabStore.deleteTab(key);
      this.$store.dispatch("tab/removeItem", key);
    },
    hide(key) {
      // this.$refs[key][0].classList.add("hidden");
      this.$store.dispatch("tab/minItem", key);
    },
    dragTab(event) {
      let this_ = this;
      let offsetX = this_.tabStore.getoffSetX(this.curKey);
      let offsetY = this_.tabStore.getoffSetY(this.curKey);
      this_.tabStore.setcurOffsetX(
        this.curKey,
        offsetX + event.clientX - this_.entryX
      );
      this_.tabStore.setcurOffsetY(
        this.curKey,
        offsetY + event.clientY - this_.entryY
      );
      // let oldData = this_.tabStore.tabs;
      // this_.$set(this_.tabStore, "tabs", oldData);
      // console.log(this_.tabStore.tabs);
      // console.log(this_.$refs[key])
      this_.$refs[this.curKey][0].setAttribute(
        "style",
        `transform: translate(${this_.tabStore.getcurOffsetX(this.curKey)}px, 
        ${this_.tabStore.getcurOffsetY(this.curKey)}px)`
      );
    },
    dragTabStart(event, key) {
      this.curKey = key;
      this.entryX = event.clientX;
      this.entryY = event.clientY;
      this.tabStore.setcurOffsetX(key, this.tabStore.getoffSetX(key));
      this.tabStore.setcurOffsetY(key, this.tabStore.getoffSetY(key));
      this.tabStore.setismove(key, true);

      event.target.addEventListener("mousemove", this.dragTab, false);
      event.target.addEventListener("tounchmove", this.dragTab, false);
      // this.curOffsetX = this.offSetX;
      // this.curOffsetY = this.offSetY;
      // this.ismove = true;
    },
    dragTabEnd(event, key) {
      // this.offSetX = this.curOffsetX;
      // this.offSetY = this.curOffsetY;
      // this.ismove = false;
      //  this.curOffsetX = 0;
      // this.curOffsetY = 0;
      this.tabStore.setoffSetX(key, this.tabStore.getcurOffsetX(key));
      this.tabStore.setoffSetY(key, this.tabStore.getcurOffsetY(key));
      this.tabStore.setismove(key, false);
      this.tabStore.setcurOffsetX(key, 0);
      this.tabStore.setcurOffsetY(key, 0);
      this.curKey = "";

      event.target.removeEventListener("mousemove", this.dragTab);
      event.target.removeEventListener("tounchmove", this.dragTab);
    },
  },
};
</script>